import json
h = json.load(open('checkpoints/training_history.json'))
issues = []
for e in h:
    if any(v != v for v in [e.get('train_loss'), e.get('val_loss')]):  # NaN check
        issues.append(f'Epoch {e[\"epoch\"]}: NaN loss')
    m = e.get('metrics', {})
    for k,v in m.items():
        if v != v or abs(v) == float('inf'):
            issues.append(f'Epoch {e[\"epoch\"]}: {k}={v}')
if issues:
    for i in issues:
        print(i)
else:
    print('No NaN/Inf found in any of the', len(h), 'history entries')
"

